/**
 * IntentSegmentation.stories.js
 *
 * Concept: Every motion token system makes a decision about how to bound the vocabulary
 * of motion intent. This decision varies by organization. It is not universal.
 */

import { TRANSITIONS, cubicBezierCSS } from './tokens.js';
import { BASE_STYLES } from './shared-styles.js';

export default {
  title: 'Concepts/Intent Segmentation',
  parameters: { layout: 'fullscreen' },
};

// ---------------------------------------------------------------------------
// Token data per system
// ---------------------------------------------------------------------------

// Carbon
const CARBON_PRODUCTIVE_STANDARD   = 'cubic-bezier(0.2, 0, 0.38, 0.9)';
const CARBON_EXPRESSIVE_ENTRANCE   = 'cubic-bezier(0, 0, 0.3, 1)';
const CARBON_DURATION_FAST_01      = 70;
const CARBON_DURATION_MODERATE_01  = 150;

// Polaris — no expressive category
const POLARIS_EASE     = 'cubic-bezier(0.25, 0.1, 0.25, 1)';
const POLARIS_EASE_OUT = 'cubic-bezier(0.19, 0.91, 0.38, 1)';
const POLARIS_DUR_200  = 200;
const POLARIS_DUR_300  = 300;

// Primer — trajectory vocabulary
const PRIMER_TRANSITIONS = {
  enter: { duration: 400, easing: 'cubic-bezier(0.3, 0.8, 0.6, 1)' },
  exit:  { duration: 100, easing: 'cubic-bezier(0.7, 0.1, 0.75, 0.9)' },
  move:  { duration: 200, easing: 'cubic-bezier(0.6, 0, 0.2, 1)' },
  hover: { duration: 100, easing: 'cubic-bezier(0.25, 0.1, 0.25, 1)' },
};

// Uber Base — no segmentation
const UBER_EASING   = 'cubic-bezier(0.2, 0.8, 0.4, 1)';
const UBER_DURATION = 300; // timing300

// ---------------------------------------------------------------------------
// Story 1 — FourPositions
// ---------------------------------------------------------------------------
export const FourPositions = {
  name: 'Four positions on intent segmentation',
  render: () => {
    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${BASE_STYLES}
        .cols { display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px; margin-top: 8px; }
        .col { background: #fff; border: 1px solid #e0e0e0; border-radius: 8px; padding: 18px; }
        .col-name { font-size: 14px; font-weight: 700; color: #1a1a1a; margin-bottom: 2px; }
        .col-system { font-size: 11px; color: #888; text-transform: uppercase; letter-spacing: 0.07em; margin-bottom: 12px; }
        .col-position { font-size: 12px; font-weight: 600; color: #333; margin-bottom: 12px; padding: 8px 10px; border-radius: 4px; }
        .col-tokens { font-size: 11px; font-family: monospace; line-height: 1.8; color: #444; background: #f8f8f8; border-radius: 4px; padding: 10px 12px; margin-bottom: 12px; }
        .col-callout { font-size: 11px; color: #555; line-height: 1.5; font-style: italic; border-top: 1px solid #f0f0f0; padding-top: 10px; margin-top: 10px; }
        .stage { width:100%; height:50px; background:#ececec; border-radius:4px; overflow:hidden; position:relative; margin: 8px 0 4px 0; }
        .absence-block { background:#fff8f0; border:1px solid #ffddaa; border-radius:4px; padding:8px 10px; font-size:11px; color:#885500; margin-bottom:8px; }
      </style>
      <div class="page">
        <div class="concept-header">
          <div class="concept-header-title">Intent segmentation</div>
          <div class="concept-header-body">
            Every motion token system makes a decision about which kinds of motion get named, which get prohibited, and which live outside the system entirely. These positions reflect organizational priorities, not universal motion truths. The four systems shown here represent four different architectural answers to the same question: whose job is it to enforce motion intent constraints?
          </div>
        </div>

        <div class="cols">
          <!-- Column 1: Carbon — structural enforcement -->
          <div class="col">
            <div class="col-name">Structural enforcement</div>
            <div class="col-system">IBM Carbon</div>
            <div class="col-position" style="background:#f0f4ff;">Intent is a required parameter in the API</div>
            <div class="col-tokens">
motion("standard", "productive")<br>
motion("entrance", "expressive")<br>
<span style="color:#aaa;">// type + mode = required</span>
            </div>
            <div style="font-size:11px; color:#555; margin-bottom:6px;">Tab switch (productive):</div>
            <div class="stage">
              <div id="carbProd" style="width:40px;height:40px;background:#0f62fe;border-radius:4px;position:absolute;top:5px;left:5px;opacity:0;"></div>
            </div>
            <button class="play-btn" id="playCarbProd" style="margin-bottom:8px;">Play productive</button>
            <div style="font-size:11px; color:#555; margin-bottom:6px;">Modal entrance (expressive):</div>
            <div class="stage">
              <div id="carbExp" style="width:70px;height:40px;background:#0f62fe;border-radius:4px;position:absolute;top:5px;left:5px;opacity:0;"></div>
            </div>
            <button class="play-btn" id="playCarbExp">Play expressive</button>
            <div class="col-callout">Intent is a required parameter, not documentation. Every animation must be classified at the time of use.</div>
          </div>

          <!-- Column 2: Polaris — prohibition -->
          <div class="col">
            <div class="col-name">Prohibition</div>
            <div class="col-system">Shopify Polaris</div>
            <div class="col-position" style="background:#fff8f0;">No expressive category — by design</div>
            <div class="col-tokens">
motion-duration-200<br>
motion-ease<br>
motion-ease-in-out<br>
<span style="color:#aaa;">// functional only</span>
            </div>
            <div style="font-size:11px; color:#555; margin-bottom:6px;">Functional animation:</div>
            <div class="stage">
              <div id="polBox" style="width:50px;height:40px;background:#008060;border-radius:4px;position:absolute;top:5px;left:5px;opacity:0;"></div>
            </div>
            <button class="play-btn" id="playPol" style="margin-bottom:8px;">Play</button>
            <div class="absence-block">
              Absent by intent:<br>
              <span style="font-family:monospace;">motion-easing-bounce</span> — does not exist<br>
              <span style="font-family:monospace;">motion-expressive-*</span> — does not exist
            </div>
            <div class="col-callout">The vocabulary is bounded by omission. Expressive motion has no name because it has no place in this system.</div>
          </div>

          <!-- Column 3: Primer — trajectory vocabulary -->
          <div class="col">
            <div class="col-name">Trajectory vocabulary</div>
            <div class="col-system">GitHub Primer</div>
            <div class="col-position" style="background:#f0f8f4;">Intent encoded as direction, not purpose volume</div>
            <div class="col-tokens">
motion.transition.enter<br>
motion.transition.exit<br>
motion.transition.move<br>
motion.transition.hover
            </div>
            <div style="font-size:11px; color:#555; margin-bottom:4px;">All four trajectories:</div>
            ${['enter','exit','move','hover'].map((t, i) => `
              <div class="stage" style="height:38px; margin-bottom:4px;">
                <div id="prim_${t}" style="width:40px;height:30px;background:hsl(${140 + i*30},50%,40%);border-radius:4px;position:absolute;top:4px;left:${t==='exit'?'0px':'5px'};opacity:${t==='exit'?1:0};"></div>
              </div>
            `).join('')}
            <button class="play-btn" id="playPrimer">Play all</button>
            <div class="col-callout">The naming axis is direction, not purpose volume. Authors select by the element's trajectory — no intent declaration required.</div>
          </div>

          <!-- Column 4: Uber Base — no segmentation -->
          <div class="col">
            <div class="col-name">No segmentation</div>
            <div class="col-system">Uber Base</div>
            <div class="col-position" style="background:#f4f4f4;">Primitives only — intent delegated to authors</div>
            <div class="col-tokens">
timing100 = 250ms<br>
timing300 = 300ms<br>
easeOutCurve<br>
easeInCurve<br>
easeInOutCurve
            </div>
            <div style="font-size:11px; color:#555; margin-bottom:6px;">Author composes manually:</div>
            <div class="stage">
              <div id="uberBox" style="width:50px;height:40px;background:#333;border-radius:4px;position:absolute;top:5px;left:5px;opacity:0;"></div>
            </div>
            <button class="play-btn" id="playUber" style="margin-bottom:8px;">Play</button>
            <div class="absence-block" style="background:#f8f8f8; border-color:#e0e0e0; color:#777;">
              No intent layer exists.<br>
              Authors decide intent informally at point of use.
            </div>
            <div class="col-callout">No intent layer — the decision is delegated to token authors at point of use. The system provides vocabulary; it does not enforce how it is used.</div>
          </div>
        </div>

        <div class="note" style="margin-top:24px; max-width:100%;">
          These four positions are not points on a spectrum between functional and expressive. They are different architectural answers to the question: whose job is it to enforce motion intent constraints? Carbon encodes it structurally. Polaris enforces it through omission. Primer encodes it in the token name. Uber leaves it to the author.
        </div>
      </div>
    `;

    // Carbon productive
    el.querySelector('#playCarbProd').addEventListener('click', function() {
      const box = el.querySelector('#carbProd');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      box.animate(
        [{ opacity: 0, transform: 'translateX(-20px)' }, { opacity: 1, transform: 'translateX(0)' }],
        { duration: CARBON_DURATION_FAST_01, easing: CARBON_PRODUCTIVE_STANDARD, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    // Carbon expressive
    el.querySelector('#playCarbExp').addEventListener('click', function() {
      const box = el.querySelector('#carbExp');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      box.animate(
        [{ opacity: 0, transform: 'translateY(15px)' }, { opacity: 1, transform: 'translateY(0)' }],
        { duration: CARBON_DURATION_MODERATE_01, easing: CARBON_EXPRESSIVE_ENTRANCE, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    // Polaris
    el.querySelector('#playPol').addEventListener('click', function() {
      const box = el.querySelector('#polBox');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      box.animate(
        [{ opacity: 0, transform: 'translateY(8px)' }, { opacity: 1, transform: 'translateY(0)' }],
        { duration: POLARIS_DUR_200, easing: POLARIS_EASE_OUT, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    // Primer — all four
    el.querySelector('#playPrimer').addEventListener('click', function() {
      if (this._animating) return;
      this._animating = true;
      this.disabled = true;

      const configs = [
        { id: 'prim_enter', ...PRIMER_TRANSITIONS.enter, from: { opacity: 0, transform: 'translateY(12px)' }, to: { opacity: 1, transform: 'translateY(0)' } },
        { id: 'prim_exit',  ...PRIMER_TRANSITIONS.exit,  from: { opacity: 1, transform: 'translateX(0)' },   to: { opacity: 0, transform: 'translateX(30px)' } },
        { id: 'prim_move',  ...PRIMER_TRANSITIONS.move,  from: { opacity: 0, transform: 'translateX(-20px)' }, to: { opacity: 1, transform: 'translateX(0)' } },
        { id: 'prim_hover', ...PRIMER_TRANSITIONS.hover, from: { opacity: 0, transform: 'scale(0.9)' }, to: { opacity: 1, transform: 'scale(1)' } },
      ];

      let done = 0;
      configs.forEach(cfg => {
        const box = el.querySelector(`#${cfg.id}`);
        box.animate([cfg.from, cfg.to], { duration: cfg.duration, easing: cfg.easing, fill: 'forwards' })
          .onfinish = () => { done++; if (done === configs.length) { this._animating = false; this.disabled = false; } };
      });
    });

    // Uber
    el.querySelector('#playUber').addEventListener('click', function() {
      const box = el.querySelector('#uberBox');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      box.animate(
        [{ opacity: 0, transform: 'translateX(-15px)' }, { opacity: 1, transform: 'translateX(0)' }],
        { duration: UBER_DURATION, easing: UBER_EASING, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    return el;
  },
};

